// SPDX-License-Identifier: MIT
pragma solidity ^0.8.23;

// Create2可以计算出即将部署的合约地址。
contract DeployWithCreate2 {
    address public owner;

    constructor(address _owner) {
        owner = _owner;
    }
}

contract Create2Factory {
    event Deploy(address indexed addr);

    function create(uint _salt) external {
        DeployWithCreate2 deploy = new DeployWithCreate2{
            salt: bytes32(_salt)
        }(msg.sender);

        emit Deploy(address(deploy));
    }

    //create2的底层实现
    function getAddress(bytes memory bytecode, uint salt) external view returns(address) {
        bytes32 hash = keccak256(
            abi.encodePacked(
                bytes1(0xff), address(this), salt, keccak256(bytecode)
        ));
        //hash是32字节--256位，address是20字节--160位。将hash解析为160位再转为地址
        return address(uint160(uint256(hash)));
    }

    function getByteCode(address owner) external pure returns(bytes memory) {
        //type() 是 Solidity 内置元类型函数，专门获取合约编译元信息
        //creationCode：返回合约的字节码（部署字节码）
        bytes memory bytecode= type(DeployWithCreate2).creationCode;
        return abi.encodePacked(bytecode, abi.encode(owner));
    }
}

solidity合约交互/创建合约-字节码方式.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.23;

// EVM（以太坊虚拟机） 就像一个全球共用的"超级计算机"，但它只会做最简单的几件事（加、减、存、取、跳转等）。这些操作指令就是字节码。
// Solidity 写的高级代码，编译器最终会翻译成这种字节码，EVM 才能执行。
contract Factory {
    event Log(address addr);
    function deploy() external {
        bytes memory bytecode = hex"69602a60005260206000f3600052600a6016f3";
        address addr;
        //  create 操作码
        // 作用：创建一个新的合约实例。
        // 参数：create(v, p, n)
        // v：发送的 Wei 数量（这里是 0，即不转账 ETH）。
        // p：指向内存中合约字节码起始位置的指针。
        // n：要复制的字节码长度。
        assembly {
            addr := create(0,add(bytecode,0x20), 0x13)
            
        }
        require(addr != address(0), "deploy failed");
        emit Log(addr);
    }   
}

/*
--------------部署阶段，创建时代码（Creation Code）① 把"返回42"这段代码放进内存 ② 告诉EVM：取这10字节，刻成新合约   
【将运行时代码存入内存】
PUSH10 0x602a60005260206000f3 → 69602a...f3
PUSH1 0 → 6000
MSTORE → 52
【EVM 的内存每个格子是 32 字节，那个 10 字节的运行时代码被塞在最右边。】
0x00000000000000000000000000000000000000000000602a60005260206000f3
【从第22字节开始取10个字节的内容】
PUSH1 0x0a → 600a
PUSH1 0x16 → 6016
RETURN → f3
【完整字节码】
69602a60005260206000f3600052600a6016f3
--------------调用阶段，运行时代码（Runtime Code）① 把42写进内存 ② 返回32字节的42   
【生成表示42的字节码】
42的16进制表示压入栈：PUSH1 0x2a → 602a     EVM中PUSHn=0x5f+n
内存的第0个位置压入栈：PUSH1 0 → 6000
弹出两个值：MSTORE → 52
内存[0] = 42
【生成表示返回32字节的字节码】
32进制的16进制表示压入栈：PUSH1 0x20 → 6020
0的16进制表示压入栈：PUSH1 0 → 6000
从第0字节开始取32字节返回：RETURN → f3
【返回42的字节码表示】
602a60005260206000f3
*/
